INSERT INTO bjcp_styles (id, code, name, category, og_min, og_max, fg_min, fg_max, ibu_min, ibu_max, srm_min, srm_max, abv_min, abv_max, sensory_description) VALUES
  ('american-light-lager', '1A', 'American Light Lager', 'Standard American Beer', 1.028, 1.040, 0.998, 1.008, 8, 12, 2, 3, 2.8, 4.2, 'A highly carbonated, very light-bodied, nearly flavorless lager designed to be consumed very cold. Very refreshing and thirst-quenching.'),
  ('american-lager', '1B', 'American Lager', 'Standard American Beer', 1.040, 1.050, 1.004, 1.010, 8, 18, 2, 3.5, 4.2, 5.3, 'A very pale, highly-carbonated, light-bodied, well-attenuated lager with a very neutral flavor profile and low bitterness. Served very cold, it can be a very refreshing and thirst-quenching drink.'),
  ('cream-ale', '1C', 'Cream Ale', 'Standard American Beer', 1.042, 1.055, 1.006, 1.012, 8, 20, 2, 5, 4.2, 5.6, 'A clean, well-attenuated, highly carbonated, flavorful American "lawnmower" beer. Easily drinkable, smooth, and refreshing, with more character than typical American lagers, yet still subtle and restrained.'),
  ('american-wheat-beer', '1D', 'American Wheat Beer', 'Standard American Beer', 1.040, 1.055, 1.008, 1.013, 15, 30, 3, 6, 4.0, 5.5, 'A pale, refreshing grainy, doughy, or bready wheat beer with a clean fermentation profile and a variable hop character and bitterness. Its lighter body and higher carbonation contribute to its easy-drinking nature.'),
  ('international-pale-lager', '2A', 'International Pale Lager', 'International Lager', 1.042, 1.050, 1.008, 1.012, 18, 25, 2, 6, 4.5, 6.0, 'A highly-attenuated pale lager without strong flavors, typically well-balanced and highly carbonated. Served cold, it is refreshing and thirst-quenching.'),
  ('international-amber-lager', '2B', 'International Amber Lager', 'International Lager', 1.042, 1.055, 1.008, 1.014, 8, 25, 6, 14, 4.5, 6.0, 'A smooth, easily-drinkable, malty amber lager with a flavorful caramel or toast character. Usually fairly well-attenuated, often with an adjunct quality and restrained bitterness.'),
  ('international-dark-lager', '2C', 'International Dark Lager', 'International Lager', 1.044, 1.056, 1.008, 1.012, 8, 20, 14, 30, 4.2, 6.0, 'A darker, richer, and somewhat sweeter version of international pale lager with a little more body and flavor, but equally restrained in bitterness. The low bitterness leaves the malt as the primary flavor element, and the low hop levels provide very little in the way of balance.'),
  ('czech-pale-lager', '3A', 'Czech Pale Lager', 'Czech Lager', 1.028, 1.044, 1.008, 1.014, 20, 35, 3, 6, 3.0, 4.1, 'A lighter-bodied, rich, refreshing, hoppy, bitter pale Czech lager having the familiar flavors of the stronger Czech Premium Pale Lager (Pilsner-type) beer but in a lower alcohol, lighter-bodied, and slightly less intense format.'),
  ('czech-premium-pale-lager', '3B', 'Czech Premium Pale Lager', 'Czech Lager', 1.044, 1.060, 1.013, 1.017, 30, 45, 3.5, 6, 4.2, 5.8, 'A refreshing pale Czech lager with considerable malt and hop character and a long finish. The malt flavors are complex for a Pilsner-type beer. The bitterness is strong and clean but lacks harshness, which gives a well-balanced, rounded flavor impression that enhances drinkability.'),
  ('czech-amber-lager', '3C', 'Czech Amber Lager', 'Czech Lager', 1.044, 1.060, 1.013, 1.017, 20, 35, 10, 16, 4.4, 5.8, 'A malty amber Czech lager with a hop character that can vary from low to quite significant. The malt flavors also can vary, leading to different interpretations and balances ranging from drier, bready, and slightly biscuity to sweeter and somewhat caramel-like.'),
  ('czech-dark-lager', '3D', 'Czech Dark Lager', 'Czech Lager', 1.044, 1.060, 1.013, 1.017, 18, 34, 17, 35, 4.4, 5.8, 'A rich, dark, malty Czech lager with a roast character that can vary from almost absent to quite prominent. Malty balance and an interesting and complex flavor profile, with variable levels of hopping that provides a range of possible interpretations.'),
  ('munich-helles', '4A', 'Munich Helles', 'Pale Malty European Lager', 1.044, 1.048, 1.006, 1.012, 16, 22, 3, 5, 4.7, 5.4, 'A gold-colored German lager with a smooth, malty flavor and a soft, dry finish. Subtle spicy, floral, or herbal hops and restrained bitterness help keep the balance malty but not sweet, which helps make this beer a refreshing, everyday drink.'),
  ('festbier', '4B', 'Festbier', 'Pale Malty European Lager', 1.054, 1.057, 1.010, 1.012, 18, 25, 4, 6, 5.8, 6.3, 'A smooth, clean, pale German lager with a moderately strong malty flavor and a light hop character. Deftly balances strength and drinkability, with a palate impression and finish that encourages drinking. Showcases elegant German malt flavors without becoming too heavy or filling.'),
  ('helles-bock', '4C', 'Helles Bock', 'Pale Malty European Lager', 1.064, 1.072, 1.011, 1.018, 23, 35, 6, 9, 6.3, 7.4, 'A relatively pale, strong, malty German lager with a nicely attenuated finish that enhances drinkability. The hop character is generally more apparent and the malt character less deeply rich than in other Bocks.'),
  ('german-leichtbier', '5A', 'German Leichtbier', 'Pale Bitter European Beer', 1.026, 1.034, 1.006, 1.010, 15, 28, 1.5, 4, 2.4, 3.6, 'A pale, highly-attenuated, light-bodied German lager with lower alcohol and calories than standard-strength beers. Moderately bitter with noticeable malt and hop flavors, the beer is still interesting to drink.'),
  ('kolsch', '5B', 'Kolsch', 'Pale Bitter European Beer', 1.044, 1.050, 1.007, 1.011, 18, 30, 3.5, 5, 4.4, 5.2, 'A subtle, brilliantly clear, pale beer with a delicate balance of malt, fruit, and hop character, moderate bitterness, and a well-attenuated but soft finish. Freshness makes a huge difference with this beer, as the delicate character can fade quickly with age.'),
  ('german-helles-exportbier', '5C', 'German Helles Exportbier', 'Pale Bitter European Beer', 1.050, 1.058, 1.008, 1.015, 20, 30, 4, 6, 5.0, 6.0, 'A golden German lager balancing a smooth malty profile with a bitter, hoppy character in a slightly above-average body and strength beer.'),
  ('german-pils', '5D', 'German Pils', 'Pale Bitter European Beer', 1.044, 1.050, 1.008, 1.013, 22, 40, 2, 4, 4.4, 5.2, 'A pale, dry, bitter German lager featuring a prominent hop aroma. Crisp, clean, and refreshing, showing a brilliant gold color with excellent head retention.'),
  ('marzen', '6A', 'Marzen', 'Amber Malty European Lager', 1.054, 1.060, 1.010, 1.014, 18, 24, 8, 17, 5.6, 6.3, 'An amber, malty German lager with a clean, rich, toasty, bready malt flavor, restrained bitterness, and a well-attenuated finish. The overall malt impression is soft, elegant, and complex, with a rich malty aftertaste that is never cloying or heavy.'),
  ('rauchbier', '6B', 'Rauchbier', 'Amber Malty European Lager', 1.050, 1.057, 1.012, 1.016, 20, 30, 12, 22, 4.8, 6, 'A beechwood-smoked, malty, amber German lager. The expected Märzen profile of toasty-rich malt, restrained bitterness, clean fermentation, and a relatively dry finish is enhanced by a noticeable to intense smoke character.'),
  ('dunkles-bock', '6C', 'Dunkles Bock', 'Amber Malty European Lager', 1.064, 1.072, 1.013, 1.019, 20, 27, 14, 22, 6.3, 7.2, 'A strong, dark, malty German lager beer that emphasizes the malty-rich and somewhat toasty qualities of continental malts without being sweet in the finish.'),
  ('vienna-lager', '7A', 'Vienna Lager', 'Amber Bitter European Beer', 1.048, 1.055, 1.010, 1.014, 18, 30, 9, 15, 4.7, 5.5, 'A moderate-strength continental amber lager with a soft, smooth maltiness and a balanced, moderate bitterness, yet finishing relatively dry. The malt flavor is clean, bready-rich, and somewhat toasty, with an elegant impression derived from quality base malts and process, not specialty malts or adjuncts.'),
  ('altbier', '7B', 'Altbier', 'Amber Bitter European Beer', 1.044, 1.052, 1.008, 1.014, 25, 50, 9, 17, 4.3, 5.5, 'A moderately colored, well-attenuated, bitter beer with a rich maltiness balancing a strong bitterness. Light and spicy hop character complements the malt. A dry beer with a firm body and smooth palate.'),
  ('munich-dunkel', '8A', 'Munich Dunkel', 'Dark European Lager', 1.048, 1.056, 1.010, 1.016, 18, 28, 17, 28, 4.5, 5.6, 'A traditional malty brown lager from Bavaria. Deeply toasted, bready malt flavors without any roasty or burnt flavors. Smooth and rich, with a restrained bitterness and a relatively dry finish that allows for drinking in quantity.'),
  ('schwarzbier', '8B', 'Schwarzbier', 'Dark European Lager', 1.046, 1.052, 1.010, 1.016, 20, 35, 19, 30, 4.4, 5.4, 'A dark German lager that balances roasted yet smooth malt flavors with moderate hop bitterness. The lighter body, dryness, and lack of a harsh, burnt, or heavy aftertaste helps make this beer quite drinkable.'),
  ('doppelbock', '9A', 'Doppelbock', 'Strong European Beer', 1.072, 1.112, 1.016, 1.024, 16, 26, 6, 25, 7.0, 10.0, 'A strong, rich, and very malty German lager that can have both pale and dark variants. The darker versions have more richly-developed, deeper malt flavors, while the paler versions have slightly more hops and dryness.'),
  ('eisbock', '9B', 'Eisbock', 'Strong European Beer', 1.078, 1.120, 1.020, 1.035, 25, 35, 17, 30, 9.0, 14.0, 'A strong, full-bodied, rich, and malty dark German lager often with a viscous quality and strong flavors. Even though flavors are concentrated, the alcohol should be smooth and warming, not burning.'),
  ('baltic-porter', '9C', 'Baltic Porter', 'Strong European Beer', 1.060, 1.090, 1.016, 1.024, 20, 40, 17, 30, 6.5, 9.5, 'A strong, dark, malty beer with different interpretations within the Baltic region. Smooth, warming, and richly malty, with complex dark fruit flavors and a roasted flavor without burnt notes.'),
  ('weissbier', '10A', 'Weissbier', 'German Wheat Beer', 1.044, 1.053, 1.008, 1.014, 8, 15, 2, 6, 4.3, 5.6, 'A pale, refreshing, lightly-hopped German wheat beer with high carbonation, dry finish, fluffy mouthfeel, and a distinctive banana-and-clove weizen yeast fermentation profile.'),
  ('dunkles-weissbier', '10B', 'Dunkles Weissbier', 'German Wheat Beer', 1.044, 1.057, 1.008, 1.014, 10, 18, 14, 23, 4.3, 5.6, 'A moderately dark German wheat beer with a distinctive banana-and-clove weizen yeast fermentation profile, supported by a toasted bread or caramel malt flavor. Highly carbonated and refreshing, with a creamy, fluffy texture and light finish.'),
  ('weizenbock', '10C', 'Weizenbock', 'German Wheat Beer', 1.064, 1.090, 1.015, 1.022, 15, 30, 6, 25, 6.5, 9.0, 'A strong and malty German wheat beer combining the best wheat and yeast flavors of a Weissbier with the rich maltiness, strength, and body of a Bock. The style range includes Bock and Doppelbock strength, with variations for pale and dark color.'),
  ('ordinary-bitter', '11A', 'Ordinary Bitter', 'British Bitter', 1.030, 1.039, 1.007, 1.011, 25, 35, 8, 14, 3.2, 3.8, 'Low gravity, alcohol, and carbonation make this an easy-drinking session beer. The malt profile can vary in flavor and intensity, but should never override the overall bitter impression. Drinkability is a critical component of the style.'),
  ('best-bitter', '11B', 'Best Bitter', 'British Bitter', 1.040, 1.048, 1.008, 1.012, 25, 40, 8, 16, 3.8, 4.6, 'A flavorful, yet refreshing, session beer. Some examples can be more malt balanced, but this should not override the overall bitter impression. Drinkability is a critical component of the style.'),
  ('strong-bitter', '11C', 'Strong Bitter', 'British Bitter', 1.048, 1.060, 1.010, 1.016, 30, 50, 8, 18, 4.6, 6.2, 'An average-strength to moderately-strong British bitter ale. The balance may vary between fairly even between malt and hops to somewhat bitter. Drinkability is a critical component of the style. A rather broad style that allows for considerable interpretation by the brewer.'),
  ('british-golden-ale', '12A', 'British Golden Ale', 'Pale Commonwealth Beer', 1.038, 1.053, 1.006, 1.012, 20, 45, 2, 5, 3.8, 5.0, 'A hop-forward, average-strength to moderately-strong pale bitter. Drinkability and a refreshing quality are critical components of the style, as it was initially a summer seasonal beer.'),
  ('australian-sparkling-ale', '12B', 'Australian Sparkling Ale', 'Pale Commonwealth Beer', 1.038, 1.050, 1.004, 1.006, 20, 35, 4, 7, 4.5, 6.0, 'A well-balanced, pale, highly carbonated, and refreshing ale suitable for drinking in a hot climate. Fairly bitter, with a moderate herbal-spicy hop and pome fruit ester profile. Smooth, neutral malt flavors with a fuller body but a crisp, highly-attenuated finish.'),
  ('english-ipa', '12C', 'English IPA', 'Pale Commonwealth Beer', 1.050, 1.070, 1.010, 1.015, 40, 60, 6, 14, 5.0, 7.5, 'A bitter, moderately-strong, very well-attenuated pale British ale with a dry finish and a hoppy aroma and flavor. Classic British ingredients provide the most authentic flavor profile.'),
  ('dark-mild', '13A', 'Dark Mild', 'Brown British Beer', 1.030, 1.038, 1.008, 1.013, 10, 25, 14, 25, 3.0, 3.8, 'A dark, low-gravity, malt-focused British session ale readily suited to drinking in quantity. Refreshing, yet flavorful for its strength, with a wide range of dark malt or dark sugar expression.'),
  ('british-brown-ale', '13B', 'British Brown Ale', 'Brown British Beer', 1.040, 1.052, 1.008, 1.013, 20, 30, 12, 22, 4.2, 5.9, 'A malty, caramelly, brown British ale without the roasted flavors of a Porter. Balanced and flavorful, but usually a little stronger than most average UK beers.'),
  ('english-porter', '13C', 'English Porter', 'Brown British Beer', 1.040, 1.052, 1.008, 1.014, 18, 35, 20, 30, 4.0, 5.4, 'A moderate-strength dark brown English ale with a restrained roasty, bitter character. May have a range of roasted flavors, generally without burnt qualities, and often has a malty chocolate and caramel profile.'),
  ('scottish-light', '14A', 'Scottish Light', 'Scottish Ale', 1.030, 1.035, 1.010, 1.013, 10, 20, 17, 25, 2.5, 3.3, 'A low-alcohol, malty beer with light caramel, toast, toffee, and fruit flavors. A slight roast dryness offsets the residual sweetness in the finish, with the bitterness perceived only to keep the beer from being cloying.'),
  ('scottish-heavy', '14B', 'Scottish Heavy', 'Scottish Ale', 1.035, 1.040, 1.010, 1.015, 10, 20, 12, 20, 3.3, 3.9, 'A lower-alcohol, malty beer with light caramel, toast, toffee, and fruity flavors. A slight roast dryness offsets the residual sweetness in the finish, with the bitterness perceived only to keep the beer from being cloying.'),
  ('scottish-export', '14C', 'Scottish Export', 'Scottish Ale', 1.040, 1.060, 1.010, 1.016, 15, 30, 12, 20, 3.9, 6.0, 'A moderate-strength, malty beer with light caramel, toast, toffee, and fruit flavors. A slight roast dryness offsets the residual sweetness in the finish, with the bitterness perceived only to keep the beer from being cloying.'),
  ('irish-red-ale', '15A', 'Irish Red Ale', 'Irish Beer', 1.036, 1.046, 1.010, 1.014, 18, 28, 9, 14, 3.8, 5.0, 'An easy-drinking pint, often with subtle flavors. Slightly malty in the balance sometimes with an initial soft toffee or caramel sweetness, a slightly grainy biscuity palate, and a touch of roasted dryness in the finish. Some versions can emphasize the caramel and sweetness more, while others will favor the grainy palate and roasted dryness.'),
  ('irish-stout', '15B', 'Irish Stout', 'Irish Beer', 1.036, 1.044, 1.007, 1.011, 25, 45, 25, 40, 3.8, 5.0, 'A black beer with a pronounced roasted flavor, often similar to coffee. The balance can range from fairly even to quite bitter, with the more balanced versions having a little malty sweetness and the bitter versions being quite dry. Draught versions typically are creamy from a nitro pour, but bottled versions will not have this dispense-derived character. The roasted flavor can range from dry and coffee-like to somewhat chocolaty.'),
  ('irish-extra-stout', '15C', 'Irish Extra Stout', 'Irish Beer', 1.052, 1.062, 1.010, 1.014, 35, 50, 30, 40, 5.0, 6.5, 'A fuller-bodied black beer with a pronounced roasted flavor, often similar to coffee and dark chocolate with some malty complexity. The balance can range from moderately bittersweet to bitter, with the more balanced versions having up to moderate malty richness and the bitter versions being quite dry.'),
  ('sweet-stout', '16A', 'Sweet Stout', 'Dark British Beer', 1.044, 1.060, 1.012, 1.024, 20, 40, 30, 40, 4.0, 6.0, 'A very dark, sweet, full-bodied, slightly roasty stout that can suggest coffee-and-cream, or sweetened espresso.'),
  ('oatmeal-stout', '16B', 'Oatmeal Stout', 'Dark British Beer', 1.045, 1.065, 1.010, 1.018, 25, 40, 22, 40, 4.2, 5.9, 'A dark, roasty, full-bodied stout with enough sweetness to support the oat backbone. The sweetness, balance, and oatmeal impression can vary considerably.'),
  ('tropical-stout', '16C', 'Tropical Stout', 'Dark British Beer', 1.056, 1.075, 1.010, 1.018, 30, 50, 30, 40, 5.5, 8.0, 'A very dark, sweet, fruity, moderately strong stout with smooth, roasty flavors, yet no burnt harshness.'),
  ('foreign-extra-stout', '16D', 'Foreign Extra Stout', 'Dark British Beer', 1.056, 1.075, 1.010, 1.018, 50, 70, 30, 40, 6.3, 8.0, 'A very dark, rich, moderately strong, fairly dry stout with prominent roast flavors.'),
  ('british-strong-ale', '17A', 'British Strong Ale', 'Strong British Ale', 1.055, 1.080, 1.015, 1.022, 30, 60, 8, 22, 5.5, 8.0, 'An ale of respectable alcoholic strength, traditionally bottled-conditioned and cellared. Can have a wide range of interpretations, but most will have varying degrees of malty richness, late hops and bitterness, fruity esters, and alcohol warmth. The malt and adjunct flavors and intensity can vary widely, but any combination should result in an agreeable palate experience.'),
  ('old-ale', '17B', 'Old Ale', 'Strong British Ale', 1.055, 1.088, 1.015, 1.022, 30, 60, 10, 22, 5.5, 9.0, 'A stronger-than-average English ale, though usually not as strong or rich as an English Barley Wine, but usually malty. Warming. Shows positive maturation effects of a well-kept, aged beer.'),
  ('wee-heavy', '17C', 'Wee Heavy', 'Strong British Ale', 1.070, 1.130, 1.018, 1.040, 17, 35, 14, 25, 6.5, 10.0, 'Rich, sweet malt depth with caramel, toffee, and fruity flavors. Full-bodied and chewy, with warming alcohol. Restrained bitterness, but not cloying or syrupy.'),
  ('english-barley-wine', '17D', 'English Barley Wine', 'Strong British Ale', 1.080, 1.120, 1.018, 1.030, 35, 70, 8, 22, 8.0, 12.0, 'A strong and richly malty ale with a pleasant fruity or hoppy depth. A wintertime sipper with a full, chewy body and warming alcohol.'),
  ('blonde-ale', '18A', 'Blonde Ale', 'Pale American Ale', 1.038, 1.054, 1.008, 1.013, 15, 28, 3, 6, 3.8, 5.5, 'Easy-drinking, approachable, malt oriented American craft beer, often with interesting fruit, hop, or character malt notes. Well-balanced and clean, is a refreshing pint without aggressive flavors.'),
  ('american-pale-ale', '18B', 'American Pale Ale', 'Pale American Ale', 1.045, 1.060, 1.010, 1.015, 30, 50, 5, 10, 4.5, 6.2, 'An average-strength, hop-forward, pale American craft beer with sufficient supporting malt to make the beer balanced and drinkable. The clean hop presence can reflect classic or modern American or New World hop varieties with a wide range of characteristics.'),
  ('american-amber-ale', '19A', 'American Amber Ale', 'Amber and Brown American Beer', 1.045, 1.060, 1.010, 1.015, 25, 40, 10, 17, 4.5, 6.2, 'An amber, hoppy, moderate-strength American craft beer with a malty caramel flavor. The balance can vary quite a bit, with some versions being fairly malty and others being aggressively hoppy. Hoppy and bitter versions should not have clashing flavors with the caramel malt profile.'),
  ('california-common', '19B', 'California Common', 'Amber and Brown American Beer', 1.048, 1.054, 1.011, 1.014, 30, 45, 9, 14, 4.5, 5.5, 'A toasty and caramelly, fairly bitter, standard-strength beer with an interesting fruitiness and rustic, woody hop character. Smooth and well carbonated.'),
  ('american-brown-ale', '19C', 'American Brown Ale', 'Amber and Brown American Beer', 1.045, 1.060, 1.010, 1.016, 20, 30, 18, 35, 4.3, 6.2, 'A malty but hoppy standard-strength American ale frequently with chocolate and caramel flavors. The hop flavor and aroma complement and enhance the malt rather than clashing with it.'),
  ('american-porter', '20A', 'American Porter', 'American Porter and Stout', 1.050, 1.070, 1.012, 1.018, 25, 50, 22, 40, 4.8, 6.5, 'A malty, bitter, and often somewhat hoppy dark beer with a balanced, roasted, and frequently chocolatey character.'),
  ('american-stout', '20B', 'American Stout', 'American Porter and Stout', 1.050, 1.075, 1.010, 1.022, 35, 75, 30, 40, 5.0, 7.0, 'A fairly strong, highly roasted, bitter, hoppy dark stout. The body and dark flavors typical of stouts with a more aggressive American hop character and bitterness.'),
  ('imperial-stout', '20C', 'Imperial Stout', 'American Porter and Stout', 1.075, 1.115, 1.018, 1.030, 50, 90, 30, 40, 8.0, 12.0, 'An intensely-flavored, very strong, very dark stout with a broad range of interpretations. Roasty-burnt malt with a depth of dark or dried fruit flavors, and a warming, bittersweet finish. Despite the intense flavors, the components need to meld together to create a complex, harmonious beer, not a hot mess -- sometimes only accomplished with age.'),
  ('american-ipa', '21A', 'American IPA', 'IPA', 1.056, 1.070, 1.008, 1.014, 40, 70, 6, 14, 5.5, 7.5, 'A decidedly hoppy and bitter, moderately strong, pale American ale. The balance is hop-forward, with a clean fermentation profile, dryish finish, and clean, supporting malt allowing a creative range of hop character to shine through.'),
  ('specialty-ipa', '21B', 'Specialty IPA', 'IPA', 1.046, 1.057, 0.990, 1.004, 20, 30, 2, 4, 6.0, 7.5, 'A very pale, hop-forward American IPA variant with a bone-dry finish, very high carbonation, and a restrained bitterness level. Can be suggestive of a sparkling white wine or Champagne. The hop character is modern, and emphasizes flavor and aroma dimensions.'),
  ('hazy-ipa', '21C', 'Hazy IPA', 'IPA', 1.060, 1.085, 1.010, 1.015, 25, 60, 3, 7, 6.0, 9.0, 'An American IPA with intense fruit flavors and aromas, a soft body, smooth mouthfeel, and often opaque with substantial haze. Less perceived bitterness than traditional IPAs but always massively hop-forward.'),
  ('double-ipa', '22A', 'Double IPA', 'Strong American Ale', 1.065, 1.085, 1.008, 1.018, 60, 100, 6, 14, 7.5, 10.0, 'An intensely hoppy, fairly strong, bitter pale ale without the big, rich, complex maltiness, residual sweetness, and body of an American Barleywine. Strongly hopped, but clean, dry, and lacking harshness. Despite showing its strength, drinkability is an important consideration.'),
  ('american-strong-ale', '22B', 'American Strong Ale', 'Strong American Ale', 1.062, 1.090, 1.014, 1.024, 50, 100, 7, 18, 6.3, 10.0, 'A malty, bitter, and strong American Ale fitting in the space between American Barleywine, Double IPA, and Red IPA. The malty and hoppy flavors can be quite strong, but are generally in balance.'),
  ('american-barleywine', '22C', 'American Barleywine', 'Strong American Ale', 1.080, 1.120, 1.016, 1.030, 50, 100, 9, 18, 8.0, 12.0, 'A very strong, malty, hoppy, bitter American ale with a rich palate, full mouthfeel, and warming aftertaste, suitable for contemplative sipping.'),
  ('wheatwine', '22D', 'Wheatwine', 'Strong American Ale', 1.080, 1.120, 1.016, 1.030, 30, 60, 6, 14, 8.0, 12.0, 'A richly textured, high alcohol sipping beer with a significant grainy, bready flavor, and a sleek body. The emphasis is first on the bready, wheaty flavors with malt, hops, fruity yeast, and alcohol complexity.'),
  ('berliner-weisse', '23A', 'Berliner Weisse', 'European Sour Ale', 1.028, 1.032, 1.003, 1.006, 3, 8, 2, 3, 2.8, 3.8, 'A very pale, refreshing, low-alcohol German wheat beer with a clean lactic sourness and a very high carbonation level. A light bread dough malt flavor supports the sourness, which shouldn''t seem artificial. A gentle fruitiness is found in the best examples.'),
  ('flanders-red-ale', '23B', 'Flanders Red Ale', 'European Sour Ale', 1.048, 1.057, 1.002, 1.012, 10, 25, 10, 17, 4.6, 6.5, 'A sour and fruity oak-aged reddish-brown Belgian-style ale with supportive toasty malt flavors and fruit complexity. The dry, tannic finish supports the suggestion of a vintage red wine.'),
  ('oud-bruin', '23C', 'Oud Bruin', 'European Sour Ale', 1.040, 1.074, 1.008, 1.012, 20, 25, 17, 22, 4.0, 8.0, 'A malty, fruity, aged, somewhat sour Belgian-style brown ale with a caramel-chocolate malt flavor, and often substantial alcohol.'),
  ('lambic', '23D', 'Lambic', 'European Sour Ale', 1.040, 1.054, 1.001, 1.010, 0, 10, 3, 6, 5.0, 6.5, 'A fairly sour, often moderately funky, wild Belgian wheat beer with sourness taking the place of hop bitterness in the balance. Traditionally served uncarbonated as a café drink.'),
  ('gueuze', '23E', 'Gueuze', 'European Sour Ale', 1.040, 1.054, 1.000, 1.006, 0, 10, 5, 6, 5.0, 8.0, 'A very refreshing, highly carbonated, pleasantly sour but balanced wild Belgian wheat beer. The wild beer character can be complex and varied, combining sour, funky, and fruity flavors.'),
  ('fruit-lambic', '23F', 'Fruit Lambic', 'European Sour Ale', 1.040, 1.060, 1.000, 1.010, 0, 10, 3, 7, 5.0, 7.0, 'A complex, refreshing, pleasantly sour Belgian wheat beer blending a complementary fermented fruit character with a sour, funky Gueuze.'),
  ('gose', '23G', 'Gose', 'European Sour Ale', 1.036, 1.056, 1.006, 1.010, 5, 12, 3, 4, 4.2, 4.8, 'A tart, lightly-bittered historical central European wheat beer with a distinctive but restrained salt and coriander character. Very refreshing, with a dry finish, high carbonation, and bright flavors.'),
  ('witbier', '24A', 'Witbier', 'Belgian Ale', 1.044, 1.052, 1.008, 1.012, 8, 20, 2, 4, 4.5, 5.5, 'A pale, hazy Belgian wheat beer with spices accentuating the yeast character. A delicate, lightly spiced, moderate-strength ale that is a refreshing summer drink with its high carbonation, dry finish, and light hopping.'),
  ('belgian-pale-ale', '24B', 'Belgian Pale Ale', 'Belgian Ale', 1.048, 1.054, 1.010, 1.014, 20, 30, 8, 14, 4.8, 5.5, 'A top-fermented, all malt, average strength Belgian ale that is moderately bitter, not dry-hopped, and without strong flavors. The copper-colored beer lacks the aggressive yeast character or sourness of many Belgian beers, but has a well-balanced, malty, fruity, and often bready and toasty profile.'),
  ('biere-de-garde', '24C', 'Bière de Garde', 'Belgian Ale', 1.060, 1.080, 1.008, 1.016, 18, 28, 6, 19, 6.0, 8.5, 'A family of smooth, fairly strong, malty, lagered artisanal French beer with a range of malt flavors appropriate for the blond, amber, or brown color. All are malty yet dry, with clean flavors. Darker versions have more malt character, while paler versions can have more hops while still remaining malt-focused beers.'),
  ('belgian-blond-ale', '25A', 'Belgian Blond Ale', 'Strong Belgian Ale', 1.062, 1.075, 1.008, 1.018, 15, 30, 4, 6, 6.0, 7.5, 'A golden, moderately-strong Belgian ale with a pleasantly subtle citrusy-spicy yeast complexity, smooth malty palate, and dry, soft finish.'),
  ('saison', '25B', 'Saison', 'Strong Belgian Ale', 1.048, 1.065, 1.002, 1.008, 20, 35, 5, 22, 3.5, 9.5, 'A family of refreshing, highly attenuated, hoppy, and fairly bitter Belgian ales with a very dry finish and high carbonation. Characterized by a fruity, spicy, sometimes phenolic fermentation profile, and the use of cereal grains and sometimes spices for complexity. Several variations in strength and color exist.'),
  ('belgian-golden-strong-ale', '25C', 'Belgian Golden Strong Ale', 'Strong Belgian Ale', 1.070, 1.095, 1.005, 1.016, 22, 35, 3, 6, 7.5, 10.5, 'A very pale, highly attenuated, strong Belgian ale that is more fruity and hoppy than spicy. Complex and delicate, the dry finish, light body, and high carbonation accentuate the yeast and hop character. Sparkling carbonation and effervescent, forming a rocky white head.'),
  ('belgian-single', '26A', 'Belgian Single', 'Monastic Ale', 1.044, 1.054, 1.004, 1.010, 25, 45, 3, 5, 4.8, 6.0, 'A blond, bitter, hoppy table beer that is very dry and highly carbonated. The aggressive fruity-spicy Belgian yeast character and high bitterness is forward in the balance, with a soft, supportive grainy-sweet malt palate, and a spicy-floral hop profile.'),
  ('belgian-dubbel', '26B', 'Belgian Dubbel', 'Monastic Ale', 1.062, 1.075, 1.008, 1.018, 15, 25, 10, 17, 6.0, 7.6, 'A deep reddish-copper, moderately strong, malty, complex Belgian ale with rich malty flavors, dark or dried fruit esters, and light alcohol blended together in a malty presentation that still finishes fairly dry.'),
  ('belgian-tripel', '26C', 'Belgian Tripel', 'Monastic Ale', 1.075, 1.085, 1.008, 1.014, 20, 40, 4.5, 7, 7.5, 9.5, 'A strong, pale, somewhat spicy Belgian ale with a pleasant rounded malt flavor, firm bitterness, and dry finish. Quite aromatic, with spicy, fruity, and light alcohol notes combining with the supportive clean malt character to produce a surprisingly drinkable beverage considering the high alcohol content.'),
  ('belgian-dark-strong-ale', '26D', 'Belgian Dark Strong Ale', 'Monastic Ale', 1.075, 1.110, 1.010, 1.024, 20, 35, 12, 22, 8.0, 12.0, 'A dark, complex, very strong Belgian ale with a delicious blend of malt richness, dark fruit flavors, and spicy notes. Complex, rich, smooth, and dangerous.'),
  ('historical-beer-kentucky-common', '27B', 'Historical Beer: Kentucky Common', 'Historical Beer', 1.044, 1.055, 1.010, 1.018, 15, 30, 11, 20, 4.0, 5.5, 'A clean, dry, refreshing, slightly malty dark beer with high carbonation. Mild-tasting, with light toast and caramel flavors, served very fresh as a sessionable saloon beer.'),
  ('historical-beer-lichtenhainer', '27C', 'Historical Beer: Lichtenhainer', 'Historical Beer', 1.032, 1.040, 1.004, 1.008, 5, 12, 3, 6, 3.5, 4.7, 'A sour, smoked, lower-gravity historical central European wheat beer. Complex yet refreshing character due to high attenuation and carbonation, along with low bitterness and moderate sourness.'),
  ('historical-beer-london-brown-ale', '27D', 'Historical Beer: London Brown Ale', 'Historical Beer', 1.033, 1.038, 1.012, 1.015, 15, 20, 22, 35, 2.8, 3.6, 'A luscious, sweet, malty, low-alcohol dark brown ale, with caramel and toffee malt complexity and a sweet-tasting finish.'),
  ('historical-beer-piwo-grodziskie', '27E', 'Historical Beer: Piwo Grodziskie', 'Historical Beer', 1.028, 1.032, 1.006, 1.012, 20, 35, 3, 6, 2.5, 3.3, 'A low-gravity, bitter, oak-smoked historical central European wheat beer with a clean fermentation profile and no sourness. Highly carbonated, dry, crisp, and refreshing.'),
  ('historical-beer-pre-prohibition-lager', '27F', 'Historical Beer: Pre-Prohibition Lager', 'Historical Beer', 1.044, 1.060, 1.010, 1.015, 25, 40, 3, 6, 4.5, 6.0, 'A bitter and hoppy pale American adjunct lager, often with a robust, corny flavor profile, although more crisp and neutral-tasting versions exist.'),
  ('historical-beer-pre-prohibition-porter', '27G', 'Historical Beer: Pre-Prohibition Porter', 'Historical Beer', 1.046, 1.060, 1.010, 1.016, 20, 30, 20, 30, 4.5, 6.0, 'A historical American adaptation of English Porter by German immigrants using American ingredients, including adjuncts.'),
  ('historical-beer-roggenbier', '27H', 'Historical Beer: Roggenbier', 'Historical Beer', 1.046, 1.056, 1.010, 1.014, 10, 20, 14, 19, 4.5, 6.0, 'A Dunkles Weissbier made with rye rather than wheat, but with a greater body and light finishing hops. The rye gives a bready and peppery flavor, a creamy body, and a dry, grainy finish that blends with the distinctive banana-and-clove weizen yeast character.'),
  ('historical-beer-sahti', '27I', 'Historical Beer: Sahti', 'Historical Beer', 1.076, 1.120, 1.016, 1.038, 0, 15, 4, 22, 7.0, 11.0, 'A sweet, heavy, strong traditional Finnish farmhouse beer usually with rye and juniper, and a banana-clove yeast character.'),
  ('straight-sour-beer', '28D', 'Straight Sour Beer', 'American Wild Ale', 1.048, 1.065, 1.006, 1.013, 3, 8, 2, 3, 4.5, 7.0, 'A pale, refreshing, sour beer with a clean lactic sourness. A gentle, pale malt flavor supports the lemony sourness with moderate fruity esters.'),
  ('grape-ale', '29D', 'Grape Ale', 'Fruit Beer', 1.059, 1.075, 1.004, 1.013, 10, 30, 4, 8, 6.0, 8.5, 'Combines the profile of a sparkling wine and a relatively neutral base beer allowing the aromatic qualities of the grape to blend pleasantly with hop and yeast aromatics. Can be in a range from refreshing to complex.')
