  ('east-kent-golding', 'East Kent Golding', 'Reino Unido', 5, NULL, 'pellet', ARRAY['hervido', 'whirlpool']::text[], ARRAY['miel', 'floral', 'terroso']::text[], 'Lúpulo inglés suave para stouts y ales tradicionales.'),
